module shift_register(
    input clk,
    input load,
    input shift_enable,
    input [31:0] data,
    output reg [31:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (load)
        q <= data;
    else if (shift_enable)
        q <= {1'b0, q[31:1]};
end
endmodule
